'use client'

import React from 'react'
import FormCard from '../formcard'
import GoogleSignBtn from '../GoogleSignBtn'
import { Input } from '@/components/ui/input'
import { Label } from '@/components/ui/label'
import { Button } from '@/components/ui/button'

const LoginForm = () => {
  return (
    <FormCard
      className="w-full shadow-xl max-w-[500px] border-0 flex flex-col items-center justify-center"
      title="Welcome back"
      label="Login to Xpunt24 account"
      backButtonHref="/auth/register"
      backButtonLabel="Don't have an account? Register"
      isLogin={true}
    >
      <div className="flex flex-col gap-4 w-full">
        <div className="flex flex-col gap-1.5">
          <Label htmlFor="email">Email</Label>
          <Input id="email" type="email" placeholder="you@example.com" disabled />
        </div>
        <div className="flex flex-col gap-1.5">
          <Label htmlFor="password">Password</Label>
          <Input id="password" type="password" placeholder="••••••••" disabled />
        </div>
        <Button className="w-full" disabled>Sign In</Button>
        <div className="relative flex items-center gap-3 my-1">
          <div className="flex-1 border-t border-gray-200" />
          <span className="text-xs text-gray-400">or</span>
          <div className="flex-1 border-t border-gray-200" />
        </div>
        <GoogleSignBtn text="Sign In" />
      </div>
    </FormCard>
  )
}

export default LoginForm
